-- ============================================================
-- SOP 2: Fluxo D3D Pipeline — Gestão de Produção 3D
-- ============================================================
INSERT INTO knowledge_sops (tenant_id, title, slug, bu, category, status, priority, tags, content, author_id, version, last_reviewed_at)
VALUES (
  (SELECT id FROM tenants LIMIT 1),
  'Fluxo D3D Pipeline: Gestão de Produção 3D do Briefing à Entrega',
  'tbo-3d-015-fluxo-d3d-pipeline-producao',
  'digital-3d',
  'processo',
  'published',
  'critical',
  ARRAY['pipeline', 'd3d', 'gestão de produção', 'fluxo', '3d', 'kanban', 'cronograma'],
  E'## Fluxo D3D Pipeline: Gestão de Produção 3D do Briefing à Entrega\n\n### Objetivo\nDefinir o fluxo completo de gestão de produção da BU Digital 3D — desde a entrada do briefing até a entrega final ao cliente — usando o TBO OS como sistema de controle, garantindo previsibilidade de prazo, qualidade e visibilidade do status de cada projeto para todas as partes envolvidas.\n\n### Escopo\nAplica-se a todos os projetos de Digital 3D: renders estáticos, animações, tours 360°, implantações, plantas humanizadas e perspectivadas. Gerido pelo Líder de D3D com suporte do time de Operações. Inicia no kick-off do projeto e termina com o aceite formal do cliente.\n\n### RACI\n| Etapa | Responsável | Aprovador | Consultado | Informado |\n|-------|-------------|-----------|------------|-----------|\n| Briefing e kick-off | Atendimento + Líder D3D | Diretor Criativo | Cliente | Operações |\n| Planejamento e cronograma | Líder D3D | Operações | Time D3D | Comercial |\n| Modelagem 3D | Modelador | Líder D3D | — | — |\n| Iluminação e materiais | 3D Artist | Líder D3D | Diretor Criativo | — |\n| Render e pós-produção | 3D Artist | Líder D3D | — | — |\n| QA interno | Líder D3D | Diretor Criativo | — | Atendimento |\n| Apresentação ao cliente | Atendimento | Líder D3D | Comercial | — |\n| Incorporação de revisões | 3D Artist | Líder D3D | Cliente | Atendimento |\n| Entrega final | Atendimento | Líder D3D | — | Comercial |\n\n### Pré-requisitos\n- Contrato assinado e adiantamento recebido (quando aplicável)\n- Briefing criativo completo: plantas, referências visuais, paleta de cores, lista de peças\n- Acesso aos arquivos do projeto (plantas em DWG/PDF, referências de materialidade)\n- Projeto criado no TBO OS com todas as tarefas e cronograma\n- Líder D3D confirmou viabilidade técnica e prazo com o time\n\n### Procedimento\n\n#### Etapa 1 — Kick-off e Planejamento (Dias 1–2)\n1. Líder D3D participa da reunião de kick-off com Atendimento e cliente\n2. Valida lista de peças: quais renders, formatos, câmeras, resoluções\n3. Preenche template de escopo técnico D3D (ver template abaixo)\n4. Cria projeto no TBO OS — Módulo D3D Pipeline:\n   - Uma tarefa por peça (render/animação/tour)\n   - Define responsável, prazo interno, prazo de entrega ao cliente\n5. Define milestone de QA interno (D-2 antes da entrega ao cliente)\n6. Compartilha cronograma com Atendimento e Operações\n\n#### Etapa 2 — Modelagem (conforme cronograma)\n1. 3D Artist recebe tarefa no TBO OS com briefing técnico anexado\n2. Modela geometria seguindo plantas arquitetônicas\n3. Organiza arquivo 3D seguindo naming convention:\n   - Layers: GEOMETRIA, MOBILIARIO, PAISAGISMO, LUZES, CAMERAS\n   - Nomes de objetos: prefixo_descrição (ex: mob_sofa-3lug)\n4. Checkpoint interno com Líder D3D ao final da modelagem: aprovação antes de avançar\n5. Atualiza status da tarefa no TBO OS para "Em renderização"\n\n#### Etapa 3 — Iluminação, Materiais e Render\n1. Aplicar materiais seguindo referências do briefing criativo\n2. Configurar iluminação por tipo de ambiente (natural/artificial/exterior/interior)\n3. Testar render parcial (Vray Quick Render ou similar) para validar\n4. Submeter ao farm de render ou renderizar localmente\n5. Monitorar progresso e flags de erro\n\n#### Etapa 4 — Pós-produção (por render)\n1. Abrir em Photoshop ou Lightroom para pós-produção\n2. Aplicar ajustes de cor, contraste, detalhes de atmosfera\n3. Adicionar elementos 2D quando necessário (pessoas, carros, vegetação)\n4. Seguir SOP de pós-produção de imagens estáticas (tbo-3d-004)\n5. Salvar versão PSD + exportar JPEG/PNG conforme especificação\n\n#### Etapa 5 — QA Interno (Obrigatório D-2)\n1. Líder D3D revisa TODAS as peças com checklist de qualidade (tbo-3d-012)\n2. Itens verificados: proporções arquitetônicas, materialidade, iluminação, pós-produção, watermark, resolução\n3. Issues reportados e corrigidos antes de enviar ao cliente\n4. Atualiza status no TBO OS para "QA Aprovado"\n\n#### Etapa 6 — Apresentação ao Cliente\n1. Atendimento monta galeria de apresentação (Google Drive / portal do cliente)\n2. Envia com prazo de feedback de 5 dias úteis\n3. Consolida feedback do cliente em documento único\n4. Classifica feedbacks: dentro do escopo / fora do escopo\n5. Aditivo para feedbacks fora do escopo antes de incorporar\n\n#### Etapa 7 — Revisões e Entrega Final\n1. 3D Artist incorpora revisões aprovadas (máx. 2 rodadas no contrato padrão)\n2. QA final pelo Líder D3D antes da entrega\n3. Exportar pacote de entrega:\n   - JPEG alta resolução (mín. 300dpi para impressão, 72dpi para web)\n   - PNG sem fundo quando solicitado\n   - PSD quando contratado\n   - Pasta organizada por tipo de peça\n4. Upload na pasta de entrega no Google Drive do cliente\n5. Atendimento envia aceite formal + solicita depoimento/NPS\n6. Líder D3D fecha projeto no TBO OS e atualiza biblioteca de assets (tbo-3d-014)\n\n### Checklist de Validação\n- [ ] Lista de peças validada com cliente antes de iniciar\n- [ ] Cronograma criado no TBO OS com milestones claros\n- [ ] Checkpoint de modelagem aprovado antes do render\n- [ ] QA interno realizado com D-2 de antecedência\n- [ ] Máximo 2 rodadas de revisão aplicadas\n- [ ] Resolução e formato corretos para cada uso final\n- [ ] Assets arquivados na biblioteca D3D\n- [ ] Projeto fechado no TBO OS com NPS coletado\n\n### Ferramentas e Recursos\n- **3D**: 3ds Max, SketchUp, Rhino (conforme especialidade do artist)\n- **Render**: V-Ray, Corona Renderer, Chaos Cloud\n- **Pós-produção**: Adobe Photoshop, Lightroom\n- **Gestão**: TBO OS — Módulo D3D Pipeline\n- **Compartilhamento**: Google Drive (estrutura padrão por cliente)\n- **Referências**: Biblioteca de materiais TBO (texturas, mobiliário, árvores)\n- **QA**: Checklist tbo-3d-012\n\n### SLAs e Métricas\n| Tipo de Peça | SLA Interno | SLA Cliente |\n|-------------|-------------|-------------|\n| Render estático simples | 3 dias úteis | 5 dias úteis |\n| Render estático complexo | 5 dias úteis | 7 dias úteis |\n| Planta humanizada | 2 dias úteis | 3 dias úteis |\n| Tour 360° | 7 dias úteis | 10 dias úteis |\n| Animação até 60s | 10 dias úteis | 15 dias úteis |\n| **Revisões** | 1-2 dias úteis | 2 rodadas inclusas |\n\n**KPIs do Pipeline D3D:**\n- Prazo cumprido: ≥90% dos projetos\n- QA interno: 100% das peças revisadas antes de enviar ao cliente\n- Revisões dentro do escopo: ≤2 rodadas em 85% dos projetos\n- NPS médio: ≥8.5\n\n### Troubleshooting\n\n**Plantas arquitetônicas incompletas ou com erros**\n→ Não iniciar modelagem. Solicitar ao Atendimento esclarecimento com o cliente. Registrar bloqueio no TBO OS.\n\n**Render com artefatos, ruído excessivo ou erro de iluminação**\n→ Aumentar samples de render. Verificar configurações de GI e iluminação. Nunca entregar render com qualidade inferior ao padrão TBO.\n\n**Prazo em risco por volume de peças**\n→ Escalar para Líder D3D em D-3. Avaliar: farm de render, terceirização de peças menos críticas, negociação de prazo via Atendimento.\n\n**Cliente solicita mudança de escopo (câmeras, estilo, peças novas)**\n→ Paralisar, emitir aditivo comercial. Só retomar após aprovação formal.\n\n**Arquivos do cliente incompatíveis (formatos obsoletos, sem layers)**\n→ Solicitar novo arquivo ou cobrar hora adicional de retrabalho técnico.\n\n### Template Anexo — Escopo Técnico D3D\n\n```markdown\n# Escopo Técnico D3D — [CLIENTE] / [EMPREENDIMENTO]\nData: _______ | Líder D3D: _______ | Prazo de entrega: _______\n\n## Lista de Peças\n| # | Tipo | Câmera/Descrição | Resolução | Formato | Prazo Interno |\n|---|------|-----------------|-----------|---------|---------------|\n| 1 | Render Ext | Fachada Principal | 5000x3000px | JPEG | _______ |\n| 2 | Render Int | Living Room | 4000x3000px | JPEG | _______ |\n| 3 | Planta Human. | Tipo A - 3 dorms | 4200x2970 (A3) | PNG | _______ |\n\n## Referências Aprovadas\n- Moodboard: [LINK]\n- Paleta de cores: [LINK]\n- Estilo de iluminação: [descrição]\n- Público-alvo: [perfil]\n\n## Observações Técnicas\n- Software principal: _______ | Render engine: _______\n- Farm de render: Sim / Não | Estimativa de render: ___h\n- Elementos especiais: vegetação específica / pessoa / carro / etc.\n\n## Aprovação de Escopo\n- Líder D3D: _________________ Data: _______\n- Atendimento: _________________ Data: _______\n```',
  NULL,
  1,
  NOW()
)
ON CONFLICT (tenant_id, slug) DO UPDATE SET
  title = EXCLUDED.title,
  content = EXCLUDED.content,
  author_id = EXCLUDED.author_id,
  updated_at = now();

